mapper.select:
select v.*,
       case when exists (
           select 1 from tbl_post_like pl2
           where pl2.post_id = v.id and pl2.member_id = #{memberId}
       ) then true else false end as is_liked,
       case when exists (
           select 1 from tbl_bookmark b
           where b.post_id = v.id and b.member_id = #{memberId}
       ) then true else false end as is_bookmarked
from view_post_feed v
where v.id = #{id}

select v.*,
       case when exists (
           select 1 from tbl_post_like pl2
           where pl2.post_id = v.id and pl2.member_id = #{memberId}
       ) then true else false end as is_liked,
       case when exists (
           select 1 from tbl_bookmark b
           where b.post_id = v.id and b.member_id = #{memberId}
       ) then true else false end as is_bookmarked
from view_post_feed v
where v.member_id not in (select bl.blocked_id from tbl_block bl where bl.blocker_id = #{memberId})
  and v.member_id not in (select r.target_id from tbl_report r where r.reporter_id = #{memberId} and r.target_type = 'member')
  and v.id not in (select r.target_id from tbl_report r where r.reporter_id = #{memberId} and r.target_type = 'post')
order by v.created_datetime desc
limit #{criteria.count}
offset #{criteria.offset}

select v.*,
case when exists (
select 1 from tbl_post_like pl2
where pl2.post_id = v.id and pl2.member_id = #{postSearch.memberId}
) then true else false end as is_liked,
case when exists (
select 1 from tbl_bookmark b
where b.post_id = v.id and b.member_id = #{postSearch.memberId}
) then true else false end as is_bookmarked
from view_post_feed v
where v.member_id not in (select bl.blocked_id from tbl_block bl where bl.blocker_id = #{postSearch.memberId})
and v.member_id not in (select r.target_id from tbl_report r where r.reporter_id = #{postSearch.memberId} and r.target_type = 'member')
and v.id not in (select r.target_id from tbl_report r where r.reporter_id = #{postSearch.memberId} and r.target_type = 'post')

    and (v.post_title like concat('%', #{postSearch.keyword}, '%')
    or v.post_content like concat('%', #{postSearch.keyword}, '%'))



        order by v.like_count desc


        order by v.created_datetime desc


limit #{criteria.count}
offset #{criteria.offset}
